#include <stdio.h>
#define MOD 1000000007
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        long long dp[N + 1][N + 1] = {0};
        for (int i = 1; i <= N; i++) {
            dp[i][i] = 26;
            for (int j = 1; j < i; j++) {
                dp[i][j] = (dp[i - 1][j] * 26 + dp[i - 1][j - 1] * 26) % MOD;
            }
        }
        long long ans = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                ans = (ans + dp[i][j]) % MOD;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

